// This Function Node splits aggregated observers into individual items
// so each observer gets a personalized email

const items = [];

for (const item of $input.all()) {
  // Split the aggregated observer fields into arrays
  const observerEmails = (item.json.observer_emails || '').split(',');
  const observerFirstNames = (item.json.observer_first_names || '').split(',');
  const observerLastNames = (item.json.observer_last_names || '').split(',');

  // Loop through each observer and create a new item
  for (let i = 0; i < observerEmails.length; i++) {
    const email = observerEmails[i]?.trim();
    if (!email) continue; // skip empty emails

    items.push({
      json: {
        ...item.json,  // keep all existing attachment & task fields
        observer_email: email,
        observer_first_name: observerFirstNames[i]?.trim() || '',
        observer_last_name: observerLastNames[i]?.trim() || ''
      }
    });
  }
}

return items;

